mapper.select:
SELECT r.id AS "registerId", r.case_number AS "caseNumber", r.real_name AS "realName", r.gender AS "gender", r.age AS "age", r.visit_date AS "visitDate", r.visit_state AS "visitState", r.check_in_time AS "checkInTime", r.noon AS "noon", d.dept_name AS "deptName", e.realname AS "physicianName", ac.chief_complaint AS "chiefComplaint", ac.symptom_duration AS "symptomDuration", ac.history_summary AS "historySummary", ac.allergy_summary AS "allergySummary", ac.medication_summary AS "medicationSummary", ac.ai_summary AS "aiSummary", ac.suggested_exam AS "suggestedExam", CASE WHEN ac.id IS NULL THEN FALSE ELSE TRUE END AS "hasAiConsultation" FROM register r LEFT JOIN department d ON d.id = r.deptment_id LEFT JOIN employee e ON e.id = r.employee_id LEFT JOIN LATERAL ( SELECT * FROM ai_consultation_record acr WHERE acr.register_id = r.id AND acr.consultation_state = 'completed' ORDER BY acr.completion_time DESC NULLS LAST, acr.creation_time DESC LIMIT 1 ) ac ON TRUE WHERE (r.visit_state = 1 AND r.check_in_time IS NOT NULL) OR r.visit_state IN (2, 5, 6)
AND r.employee_id = #{employeeId}
AND (r.case_number ILIKE CONCAT('%', #{keyword}, '%') OR r.real_name ILIKE CONCAT('%', #{keyword}, '%'))
ORDER BY r.visit_state DESC, r.check_in_time ASC NULLS LAST, r.id DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM register r WHERE (r.visit_state = 1 AND r.check_in_time IS NOT NULL) OR r.visit_state IN (2, 5, 6)
AND r.employee_id = #{employeeId}
AND (r.case_number ILIKE CONCAT('%', #{keyword}, '%') OR r.real_name ILIKE CONCAT('%', #{keyword}, '%'))

SELECT COALESCE(SUM(CASE WHEN r.visit_state = 3 THEN 1 ELSE 0 END), 0) AS "totalCompletedVisits", COALESCE(SUM(CASE WHEN r.visit_state = 3 AND r.visit_date::date = CURRENT_DATE THEN 1 ELSE 0 END), 0) AS "todayCompletedVisits", COALESCE(COUNT(DISTINCT CASE WHEN r.visit_state IN (2, 3, 5, 6) AND r.patient_id IS NOT NULL THEN r.patient_id END), 0) AS "uniquePatientsServed", COALESCE(SUM(CASE WHEN r.visit_state IN (2, 3, 5, 6) THEN 1 ELSE 0 END), 0) AS "totalEncounters", ( SELECT COUNT(*) FROM check_request cr INNER JOIN register rr ON rr.id = cr.register_id
rr.employee_id = #{employeeId}
) AS "totalCheckOrders", ( SELECT COUNT(*) FROM inspection_request ir INNER JOIN register rr ON rr.id = ir.register_id
rr.employee_id = #{employeeId}
) AS "totalInspectionOrders", ( SELECT COUNT(*) FROM check_request cr INNER JOIN register rr ON rr.id = cr.register_id WHERE rr.visit_date::date = CURRENT_DATE
AND rr.employee_id = #{employeeId}
) AS "todayCheckOrders", ( SELECT COUNT(*) FROM inspection_request ir INNER JOIN register rr ON rr.id = ir.register_id WHERE rr.visit_date::date = CURRENT_DATE
AND rr.employee_id = #{employeeId}
) AS "todayInspectionOrders" FROM register r
r.employee_id = #{employeeId}

